/*
 * Secure BLE Pairing Implementation with LE Secure Connections
 * ESP32 BLE Stack - Numeric Comparison Pairing
 */

#include "esp_bt.h"
#include "esp_gap_ble_api.h"
#include "esp_gatts_api.h"
#include "esp_bt_main.h"
#include "esp_gatt_common_api.h"
#include "esp_log.h"
#include "nvs_flash.h"

static const char *TAG = "BLE_SECURE";

/* Security parameters */
static esp_ble_auth_req_t auth_req = ESP_LE_AUTH_REQ_SC_MITM_BOND;
static esp_ble_io_cap_t iocap = ESP_IO_CAP_OUT;  // Display only for numeric comparison
static uint8_t key_size = 16;  // Maximum encryption key size
static uint8_t init_key = ESP_BLE_ENC_KEY_MASK | ESP_BLE_ID_KEY_MASK;
static uint8_t rsp_key = ESP_BLE_ENC_KEY_MASK | ESP_BLE_ID_KEY_MASK;
static uint32_t passkey = 0;  // Numeric comparison passkey

/**
 * Configure secure BLE GAP security parameters
 */
void configure_ble_security(void)
{
    /* Set IO capability to display for numeric comparison */
    esp_ble_io_cap_t iocap = ESP_IO_CAP_OUT;
    esp_ble_gap_set_security_param(ESP_BLE_SM_IOCAP_MODE, &iocap, sizeof(uint8_t));

    /* Require Secure Connections with MITM protection */
    esp_ble_auth_req_t auth_req = ESP_LE_AUTH_REQ_SC_MITM_BOND;
    esp_ble_gap_set_security_param(ESP_BLE_SM_AUTHEN_REQ_MODE, &auth_req, sizeof(uint8_t));

    /* Set maximum encryption key size (128-bit) */
    uint8_t key_size = 16;
    esp_ble_gap_set_security_param(ESP_BLE_SM_MAX_KEY_SIZE, &key_size, sizeof(uint8_t));

    /* Configure key distribution for bonding */
    uint8_t init_key = ESP_BLE_ENC_KEY_MASK | ESP_BLE_ID_KEY_MASK;
    uint8_t rsp_key = ESP_BLE_ENC_KEY_MASK | ESP_BLE_ID_KEY_MASK;
    esp_ble_gap_set_security_param(ESP_BLE_SM_SET_INIT_KEY, &init_key, sizeof(uint8_t));
    esp_ble_gap_set_security_param(ESP_BLE_SM_SET_RSP_KEY, &rsp_key, sizeof(uint8_t));

    /* Enable secure connections only mode (disable legacy pairing) */
    uint8_t sc_only_mode = 1;
    esp_ble_gap_set_security_param(ESP_BLE_SM_ONLY_ACCEPT_SPECIFIED_SEC_AUTH, &sc_only_mode, sizeof(uint8_t));

    ESP_LOGI(TAG, "BLE security configured: LESC with numeric comparison");
    ESP_LOGI(TAG, "JustWorks pairing DISABLED");
    ESP_LOGI(TAG, "Legacy pairing DISABLED");
}

/**
 * GAP event handler for secure pairing
 */
void gap_event_handler(esp_gap_ble_cb_event_t event, esp_ble_gap_cb_param_t *param)
{
    switch (event) {
    case ESP_GAP_BLE_NC_REQ_EVT:
        /* Numeric Comparison request */
        ESP_LOGI(TAG, "Numeric comparison pairing request");
        ESP_LOGI(TAG, "Please verify this passkey: %06" PRIu32, param->ble_security.key_notif.passkey);

        /* Display passkey to user (on device screen/LED)
         * User must verify passkey matches on both devices */
        passkey = param->ble_security.key_notif.passkey;

        /* Auto-accept for testing - REMOVE IN PRODUCTION */
        // esp_ble_confirm_reply(param->ble_security.key_notif.bd_addr, true);

        /* Production: Wait for user button press to confirm */
        ESP_LOGI(TAG, "Waiting for user confirmation...");
        break;

    case ESP_GAP_BLE_PASSKEY_REQ_EVT:
        /* Passkey entry request (alternative to numeric comparison) */
        ESP_LOGI(TAG, "Passkey entry required");
        /* In production, get passkey from user input */
        uint32_t user_passkey = 123456;  // Replace with actual user input
        esp_ble_passkey_reply(param->ble_security.ble_req.bd_addr, true, user_passkey);
        break;

    case ESP_GAP_BLE_SEC_REQ_EVT:
        /* Security request from peer device */
        ESP_LOGI(TAG, "Security request from peer");
        esp_ble_gap_security_rsp(param->ble_security.ble_req.bd_addr, true);
        break;

    case ESP_GAP_BLE_AUTH_CMPL_EVT:
        /* Authentication complete */
        if (param->ble_security.auth_cmpl.success) {
            ESP_LOGI(TAG, "Authentication successful!");
            ESP_LOGI(TAG, "Device bonded: %02x:%02x:%02x:%02x:%02x:%02x",
                     param->ble_security.auth_cmpl.bd_addr[0],
                     param->ble_security.auth_cmpl.bd_addr[1],
                     param->ble_security.auth_cmpl.bd_addr[2],
                     param->ble_security.auth_cmpl.bd_addr[3],
                     param->ble_security.auth_cmpl.bd_addr[4],
                     param->ble_security.auth_cmpl.bd_addr[5]);
            ESP_LOGI(TAG, "Authentication mode: %d", param->ble_security.auth_cmpl.auth_mode);
        } else {
            ESP_LOGE(TAG, "Authentication failed! Reason: %d", param->ble_security.auth_cmpl.fail_reason);
            /* Disconnect device on authentication failure */
        }
        break;

    case ESP_GAP_BLE_KEY_EVT:
        ESP_LOGI(TAG, "Key type: %s", param->ble_security.ble_key.key_type == ESP_LE_KEY_PENC ? "PENC" :
                 param->ble_security.ble_key.key_type == ESP_LE_KEY_PID ? "PID" :
                 param->ble_security.ble_key.key_type == ESP_LE_KEY_PCSRK ? "PCSRK" :
                 param->ble_security.ble_key.key_type == ESP_LE_KEY_LENC ? "LENC" :
                 param->ble_security.ble_key.key_type == ESP_LE_KEY_LID ? "LID" : "UNKNOWN");
        break;

    default:
        break;
    }
}

/**
 * User confirmation handler (call this when user presses confirm button)
 */
void user_confirm_pairing(esp_bd_addr_t bd_addr, bool accept)
{
    esp_ble_confirm_reply(bd_addr, accept);
    if (accept) {
        ESP_LOGI(TAG, "User accepted pairing with passkey: %06" PRIu32, passkey);
    } else {
        ESP_LOGI(TAG, "User rejected pairing");
    }
}

/**
 * Initialize secure BLE stack
 */
void app_main(void)
{
    esp_err_t ret;

    /* Initialize NVS for storing bonding information */
    ret = nvs_flash_init();
    if (ret == ESP_ERR_NVS_NO_FREE_PAGES || ret == ESP_ERR_NVS_NEW_VERSION_FOUND) {
        ESP_ERROR_CHECK(nvs_flash_erase());
        ret = nvs_flash_init();
    }
    ESP_ERROR_CHECK(ret);

    /* Initialize Bluetooth controller */
    esp_bt_controller_config_t bt_cfg = BT_CONTROLLER_INIT_CONFIG_DEFAULT();
    ret = esp_bt_controller_init(&bt_cfg);
    if (ret) {
        ESP_LOGE(TAG, "Bluetooth controller init failed: %s", esp_err_to_name(ret));
        return;
    }

    ret = esp_bt_controller_enable(ESP_BT_MODE_BLE);
    if (ret) {
        ESP_LOGE(TAG, "Bluetooth controller enable failed: %s", esp_err_to_name(ret));
        return;
    }

    /* Initialize Bluedroid stack */
    ret = esp_bluedroid_init();
    if (ret) {
        ESP_LOGE(TAG, "Bluedroid init failed: %s", esp_err_to_name(ret));
        return;
    }

    ret = esp_bluedroid_enable();
    if (ret) {
        ESP_LOGE(TAG, "Bluedroid enable failed: %s", esp_err_to_name(ret));
        return;
    }

    /* Register GAP callback */
    ret = esp_ble_gap_register_callback(gap_event_handler);
    if (ret) {
        ESP_LOGE(TAG, "GAP register failed: %s", esp_err_to_name(ret));
        return;
    }

    /* Configure secure pairing */
    configure_ble_security();

    ESP_LOGI(TAG, "BLE secure pairing initialized successfully");
    ESP_LOGI(TAG, "Device is now ready for secure BLE connections");
}

/*
 * Secure GATT Server Implementation with Access Control
 * Nordic nRF52840 - Encrypted GATT Characteristics
 */

#include "ble_gatts.h"
#include "ble_srv_common.h"
#include "nrf_sdh_ble.h"
#include "nrf_log.h"

#define SMARTLOCK_SERVICE_UUID    0x1800
#define LOCK_CONTROL_CHAR_UUID    0x2A00
#define LOCK_STATUS_CHAR_UUID     0x2A01

/**
 * Define GATT characteristic with secure access control
 */
static ble_gatts_char_md_t configure_secure_char_metadata(void)
{
    ble_gatts_char_md_t char_md;
    memset(&char_md, 0, sizeof(char_md));

    /* Require read/write with authenticated+encrypted link */
    char_md.char_props.read = 1;
    char_md.char_props.write = 1;
    char_md.char_props.notify = 1;

    /* Set read permissions - require encryption + authentication */
    char_md.read_perm.sm = 1;  // Require security mode 1
    char_md.read_perm.lv = 3;  // Security level 3: Authenticated + Encrypted

    /* Set write permissions - require authentication + authorization */
    char_md.write_perm.sm = 1;
    char_md.write_perm.lv = 3;

    /* Enable CCCD for notifications */
    ble_gatts_attr_md_t cccd_md;
    memset(&cccd_md, 0, sizeof(cccd_md));
    BLE_GAP_CONN_SEC_MODE_SET_ENC_WITH_MITM(&cccd_md.read_perm);
    BLE_GAP_CONN_SEC_MODE_SET_ENC_WITH_MITM(&cccd_md.write_perm);
    cccd_md.vloc = BLE_GATTS_VLOC_STACK;
    char_md.p_cccd_md = &cccd_md;

    return char_md;
}

/**
 * Create secure GATT characteristic for lock control
 */
static uint32_t add_lock_control_characteristic(uint16_t service_handle, uint16_t *char_handle)
{
    ble_gatts_char_md_t char_md = configure_secure_char_metadata();
    ble_uuid_t char_uuid;
    ble_gatts_attr_t attr_char_value;
    ble_gatts_attr_md_t attr_md;

    /* Configure UUID */
    char_uuid.type = BLE_UUID_TYPE_BLE;
    char_uuid.uuid = LOCK_CONTROL_CHAR_UUID;

    /* Configure attribute metadata with security requirements */
    memset(&attr_md, 0, sizeof(attr_md));
    BLE_GAP_CONN_SEC_MODE_SET_ENC_WITH_MITM(&attr_md.read_perm);
    BLE_GAP_CONN_SEC_MODE_SET_ENC_WITH_MITM(&attr_md.write_perm);
    attr_md.vloc = BLE_GATTS_VLOC_STACK;
    attr_md.rd_auth = 1;  // Require authorization callback on read
    attr_md.wr_auth = 1;  // Require authorization callback on write
    attr_md.vlen = 1;

    /* Configure attribute value */
    memset(&attr_char_value, 0, sizeof(attr_char_value));
    attr_char_value.p_uuid = &char_uuid;
    attr_char_value.p_attr_md = &attr_md;
    attr_char_value.init_len = 1;
    attr_char_value.max_len = 20;
    uint8_t initial_value[1] = {0x00};  // Lock state: 0=locked, 1=unlocked
    attr_char_value.p_value = initial_value;

    /* Add characteristic to service */
    uint32_t err_code = sd_ble_gatts_characteristic_add(
        service_handle,
        &char_md,
        &attr_char_value,
        char_handle
    );

    if (err_code == NRF_SUCCESS) {
        NRF_LOG_INFO("Lock control characteristic added with encryption+authentication");
    }

    return err_code;
}

/**
 * Authorization callback for GATT operations
 */
void on_gatts_authorize_request(ble_gatts_evt_rw_authorize_request_t *p_authorize_request,
                                 uint16_t conn_handle)
{
    ble_gatts_rw_authorize_reply_params_t auth_reply;
    memset(&auth_reply, 0, sizeof(auth_reply));

    /* Check if this is a write request to lock control characteristic */
    if (p_authorize_request->type == BLE_GATTS_AUTHORIZE_TYPE_WRITE) {
        ble_gatts_evt_write_t *p_write = &p_authorize_request->request.write;

        NRF_LOG_INFO("Write authorization request:");
        NRF_LOG_INFO("  Handle: 0x%04x", p_write->handle);
        NRF_LOG_INFO("  Op: %d", p_write->op);
        NRF_LOG_INFO("  Length: %d", p_write->len);

        /* Verify connection is encrypted and authenticated */
        ble_gap_conn_sec_t conn_sec;
        uint32_t err = sd_ble_gap_conn_sec_get(conn_handle, &conn_sec);

        if (err == NRF_SUCCESS) {
            NRF_LOG_INFO("Connection security level: %d", conn_sec.sec_mode.lv);
            NRF_LOG_INFO("Encryption key size: %d", conn_sec.encr_key_size);

            /* Require security level 3 (authenticated + encrypted) */
            if (conn_sec.sec_mode.lv >= 3 && conn_sec.encr_key_size >= 16) {
                /* Additional authorization checks */
                if (validate_lock_command(p_write->data, p_write->len)) {
                    auth_reply.type = BLE_GATTS_AUTHORIZE_TYPE_WRITE;
                    auth_reply.params.write.gatt_status = BLE_GATT_STATUS_SUCCESS;
                    auth_reply.params.write.update = 1;
                    auth_reply.params.write.offset = p_write->offset;
                    auth_reply.params.write.len = p_write->len;
                    auth_reply.params.write.p_data = p_write->data;

                    NRF_LOG_INFO("Write authorized - executing lock command");
                } else {
                    auth_reply.type = BLE_GATTS_AUTHORIZE_TYPE_WRITE;
                    auth_reply.params.write.gatt_status = BLE_GATT_STATUS_ATTERR_WRITE_NOT_PERMITTED;
                    NRF_LOG_WARNING("Write rejected - invalid command format");
                }
            } else {
                auth_reply.type = BLE_GATTS_AUTHORIZE_TYPE_WRITE;
                auth_reply.params.write.gatt_status = BLE_GATT_STATUS_ATTERR_INSUF_AUTHENTICATION;
                NRF_LOG_WARNING("Write rejected - insufficient security (level %d, key %d bits)",
                               conn_sec.sec_mode.lv, conn_sec.encr_key_size * 8);
            }
        } else {
            auth_reply.type = BLE_GATTS_AUTHORIZE_TYPE_WRITE;
            auth_reply.params.write.gatt_status = BLE_GATT_STATUS_ATTERR_INSUF_AUTHENTICATION;
            NRF_LOG_ERROR("Failed to get connection security");
        }

        /* Send authorization reply */
        sd_ble_gatts_rw_authorize_reply(conn_handle, &auth_reply);
    }
}

/**
 * Validate lock control command
 */
static bool validate_lock_command(const uint8_t *data, uint16_t len)
{
    if (len < 4) {
        return false;  // Command too short
    }

    /* Command format: [CMD_TYPE(1)][NONCE(2)][CHECKSUM(1)] */
    uint8_t cmd_type = data[0];
    uint16_t nonce = (data[1] << 8) | data[2];
    uint8_t checksum = data[3];

    /* Validate command type (0x01=unlock, 0x02=lock) */
    if (cmd_type != 0x01 && cmd_type != 0x02) {
        NRF_LOG_WARNING("Invalid command type: 0x%02x", cmd_type);
        return false;
    }

    /* Verify checksum */
    uint8_t calculated_checksum = cmd_type ^ (nonce >> 8) ^ (nonce & 0xFF);
    if (checksum != calculated_checksum) {
        NRF_LOG_WARNING("Checksum mismatch: expected 0x%02x, got 0x%02x",
                       calculated_checksum, checksum);
        return false;
    }

    /* Anti-replay: verify nonce is new (implement nonce tracking) */
    // if (!is_nonce_valid(nonce)) {
    //     return false;
    // }

    return true;
}

/**
 * Main BLE event handler
 */
void ble_evt_handler(ble_evt_t const *p_ble_evt, void *p_context)
{
    switch (p_ble_evt->header.evt_id) {
    case BLE_GATTS_EVT_RW_AUTHORIZE_REQUEST:
        on_gatts_authorize_request(&p_ble_evt->evt.gatts_evt.params.authorize_request,
                                   p_ble_evt->evt.gatts_evt.conn_handle);
        break;

    case BLE_GAP_EVT_CONNECTED:
        NRF_LOG_INFO("BLE connected");
        break;

    case BLE_GAP_EVT_DISCONNECTED:
        NRF_LOG_INFO("BLE disconnected");
        break;

    default:
        break;
    }
}
